.darma-loader-darma-custom-209 {
  color: #ea580c;
height: 15px;
aspect-ratio: 5;
display: grid;
animation: darma-loader-darma-custom-209-l39-0 1s infinite linear;
}
.darma-loader-darma-custom-209:before,
.darma-loader-darma-custom-209:after {
content: "";
width: calc(140%/3);
grid-area: 1/1;
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) left,
var(--_g) right;
background-size: calc(300%/7) 100%;
animation: darma-loader-darma-custom-209-l39-1 1s infinite linear;
}
.darma-loader-darma-custom-209:after {
margin-left: auto;
--s:-1;
}
@keyframes darma-loader-darma-custom-209-l39-0 {
0%,30% {transform: rotate(0)}
50%,100% {transform: rotate(.5turn)}
}
@keyframes darma-loader-darma-custom-209-l39-1 {
30%,70% {transform:translate(calc(var(--s,1)*400%/14))}
}

